sql:
SELECT season_name
FROM ipl_seasons
WHERE total_matches > 50;

SELECT total_matches
FROM ipl_seasons
WHERE season_id = 0;

SELECT total_matches
FROM ipl_seasons
WHERE season_id = 0;

SELECT team_name
FROM teams
WHERE team_id IN (
  SELECT winning_team_id
  FROM ipl_seasons
);

SELECT role
FROM team_rosters
WHERE team_id = 1 AND season_id = 1;

SELECT total_matches
FROM ipl_seasons
WHERE season_name = 'IPL20';

external_knowledge:
- 'First season' refers to the season with season_id = 1; 
- 'Average runs scored' is the total runs scored divided by the number of matches; 
- 'Top 5' indicates the players with the highest average runs scored per match, excluding those with no runs.

sql:
SELECT COUNT(*) AS total_matches
FROM matches
WHERE season_id = (SELECT MAX(season_id) FROM ipl_seasons);

SELECT MAX(highest_score)
FROM player_stats
WHERE player_id = 1 AND season_id = 1;
